SELECT p.product_id, p.provider_id, pr.provider_name, p.product_name, p.product_type_code_value_id, p.loan_type_code_value_id, p.repayment_type_code_value_id, p.collateral_type_code_value_id, p.rate_type_code_value_id, p.note, p.add_date, p.end_date, p.updated_at, pir.rate_id, pir.rate_base, pir.rate_min, pir.rate_max, pir.as_of_date FROM PRODUCT p LEFT JOIN PROVIDER pr ON p.provider_id = pr.provider_id
AND p.provider_id = #{req.providerId}
AND LOWER(p.product_name) LIKE '%' || LOWER(#{req.productNameKeyword}) || '%'
AND p.product_type_code_value_id = #{req.productTypeCodeValueId}
AND p.loan_type_code_value_id = #{req.loanTypeCodeValueId}
AND p.repayment_type_code_value_id = #{req.repaymentTypeCodeValueId}
AND p.collateral_type_code_value_id = #{req.collateralTypeCodeValueId}
AND p.rate_type_code_value_id = #{req.rateTypeCodeValueId}
AND (pir.rate_max IS NULL OR pir.rate_max <= #{req.maxRateUpperBound})
AND (pir.rate_min IS NULL OR pir.rate_min <= #{req.minRateUpperBound})
ORDER BY
pir.rate_min pir.rate_max p.product_name pir.as_of_date pir.rate_min
DESC ASC
OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

SELECT COUNT(1)
FROM PRODUCT p



        AND p.provider_id = #{req.providerId}


